INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('symptom_guide', 'abdominal_pain', ARRAY['ألم بطن','مغص','بطن حاد','معدة'], 'التشخيص التفريقي لألم البطن', E'## ألم البطن - التشخيص التفريقي\n\n**الربع العلوي الأيمن:** التهاب مرارة، حصوات، التهاب كبد\n**الربع العلوي الأيسر:** التهاب طحال، قرحة معدة، التهاب بنكرياس\n**الربع السفلي الأيمن:** التهاب زائدة، كيس مبيض، حمل خارجي\n**الربع السفلي الأيسر:** التهاب رتج، مغص كلوي\n**منتشر:** انسداد أمعاء، التهاب بريتون\n\n**علامات خطر:** تصلب البطن، انتفاخ، حمى عالية، قيء دموي، غياب أصوات الأمعاء', 'ar', 'Clinical', 5, true),
('symptom_guide', 'headache_types', ARRAY['صداع','شقيقة','صداع نصفي','رأس'], 'أنواع الصداع', E'## أنواع الصداع\n\n**صداع التوتر:** ضاغط ثنائي، خفيف-متوسط، بدون غثيان\n- العلاج: باراسيتامول، إدارة التوتر\n\n**الشقيقة (الصداع النصفي):** نابض أحادي، شديد، مع غثيان وحساسية للضوء\n- العلاج: تريبتان + مسكن\n\n**الصداع العنقودي:** حول العين، شديد جداً، دموع واحتقان أنف\n- العلاج: أكسجين + سوماتريبتان\n\n**⚠️ علامات خطر:** أسوأ صداع، مفاجئ، حمى + تصلب رقبة، تغير وعي، أعراض عصبية', 'ar', 'Clinical', 5, true),
('symptom_guide', 'chest_pain', ARRAY['ألم صدر','ذبحة','قلب','ضيق صدر'], 'التشخيص التفريقي لألم الصدر', E'## ألم الصدر\n\n**قلبي:** ألم ضاغط يمتد للكتف الأيسر، مع مجهود، يتحسن بالنتروجليسرين\n**جنبي:** ألم حاد يزداد مع التنفس\n**معدي:** حرقة مع الطعام، تحسن بمضادات الحموضة\n**عضلي هيكلي:** موضعي، يزداد بالضغط\n**انصمام رئوي:** ضيق تنفس مفاجئ، تسارع قلب، عوامل خطر DVT\n\n**⚠️ طوارئ:** ألم ضاغط > 20 دقيقة، ضيق تنفس شديد، تعرق بارد → اتصل بالطوارئ', 'ar', 'AHA/ESC', 5, true),
('symptom_guide', 'cough_evaluation', ARRAY['سعال','كحة','بلغم','سعال مزمن'], 'تقييم السعال', E'## تقييم السعال\n\n**حاد (< 3 أسابيع):**\n- عدوى تنفسية علوية\n- التهاب قصبات حاد\n- ذات رئة\n\n**مزمن (> 8 أسابيع):**\n- ربو / ربو كحي\n- ارتجاع معدي مريئي\n- تنقيط أنفي خلفي\n- أدوية (مثبطات ACE)\n- سل (سعال + حمى + نقص وزن)\n\n**فحوصات:** صورة صدر، فحص بلغم، spirometry\n\n**⚠️ إنذار:** دم في البلغم، نقص وزن، تدخين > 40 سنة → استبعاد سرطان رئة', 'ar', 'BTS/NICE', 5, true),
('symptom_guide', 'joint_pain', ARRAY['ألم مفاصل','التهاب مفاصل','روماتيزم','تورم مفصل'], 'أسباب ألم المفاصل', E'## ألم المفاصل\n\n**مفصل واحد حاد:**\n- نقرس: إبهام القدم، أحمر، حار\n- إنتان مفصلي: حمى + تورم → طوارئ\n- رض / إصابة\n\n**عدة مفاصل:**\n- التهاب مفاصل روماتويدي: صغيرة متناظرة، تيبس صباحي\n- فصال عظمي: كبيرة، مع العمر والسمنة\n- ذئبة: شابات، طفح فراشي\n\n**فحوصات:** ESR، CRP، RF، Anti-CCP، حمض يوريك\n\n**تحويل عاجل:** مفصل أحمر حار مع حمى', 'ar', 'EULAR/ACR', 5, true),
('symptom_guide', 'dizziness_vertigo', ARRAY['دوخة','دوار','فرتيجو','عدم توازن'], 'الدوخة والدوار', E'## الدوخة والدوار\n\n**دوار حقيقي (الغرفة تدور):**\n- BPPV: مع تغيير وضع الرأس، ثوانٍ\n- التهاب تيه: مستمر أيام، مع غثيان\n- مينير: نوبات + طنين + نقص سمع\n\n**دوخة (إحساس بعدم التوازن):**\n- هبوط ضغط وضعي\n- فقر دم\n- قلق\n- أدوية\n\n**فحوصات:** ضغط الدم واقفاً وجالساً، CBC، سكر، اختبار Dix-Hallpike\n\n**⚠️ تحويل فوري:** أعراض عصبية بؤرية، صداع شديد، ازدواج رؤية → استبعاد سكتة', 'ar', 'Clinical', 5, true),
('symptom_guide', 'palpitations', ARRAY['خفقان','تسارع قلب','عدم انتظام','نبض'], 'الخفقان', E'## الخفقان\n\n**أسباب شائعة:**\n- قلق وتوتر\n- كافيين\n- فقر دم\n- فرط درقية\n- نبضات بطينية مبكرة (PVCs)\n\n**أسباب خطيرة:**\n- رجفان أذيني\n- تسارع فوق بطيني SVT\n- تسارع بطيني VT\n\n**فحوصات:** ECG، CBC، TSH، إلكتروليتات، هولتر 24 ساعة\n\n**⚠️ طوارئ:** خفقان مع إغماء، ألم صدر، ضيق تنفس، أو مدة > 30 دقيقة', 'ar', 'AHA/ESC', 5, true),
('symptom_guide', 'urinary_symptoms', ARRAY['بول','حرقة بول','تبول متكرر','التهاب مسالك'], 'أعراض المسالك البولية', E'## أعراض المسالك البولية\n\n**التهاب مسالك سفلي (التهاب مثانة):**\n- حرقة، تكرار، إلحاح\n- العلاج: نتروفورانتوين 100 ملغ × 2 لمدة 5 أيام\n\n**التهاب مسالك علوي (التهاب حويضة):**\n- حمى، ألم خاصرة، غثيان\n- العلاج: سيبروفلوكساسين 500 ملغ × 2 لمدة 7 أيام\n\n**أسباب أخرى للتبول المتكرر:**\n- سكري\n- تضخم بروستاتا\n- فرط نشاط مثانة\n\n**⚠️ تحويل:** دم في البول بدون التهاب، حصوات كبيرة، فشل علاج', 'ar', 'NICE/EAU', 5, true),
('symptom_guide', 'skin_rash', ARRAY['طفح جلدي','حكة','أكزيما','حساسية جلد'], 'التشخيص التفريقي للطفح الجلدي', E'## الطفح الجلدي\n\n**حاك:**\n- أكزيما: جاف متقشر في الثنيات\n- شرى (أرتيكاريا): بقع مرتفعة متنقلة\n- جرب: بين الأصابع، ليلي\n- فطريات: حلقي مع حافة نشطة\n\n**غير حاك:**\n- صدفية: لويحات فضية\n- وردية: على الخدين\n- نخالية: بقعة رئيسية ثم انتشار\n\n**⚠️ طوارئ:**\n- طفح مع حمى + ألم مفاصل → استبعاد التهاب سحايا\n- فقاعات منتشرة\n- طفح لا يختفي بالضغط + حمى → سحايا', 'ar', 'BAD/Clinical', 5, true),
('symptom_guide', 'eye_redness', ARRAY['عين حمراء','التهاب ملتحمة','عين','رؤية'], 'احمرار العين', E'## احمرار العين\n\n**التهاب ملتحمة:**\n- بكتيري: إفراز صديدي → قطرة مضاد حيوي\n- فيروسي: مائي، معدي → كمادات باردة\n- تحسسي: حكة + دموع → مضاد هيستامين\n\n**التهاب قزحية:** ألم، حساسية للضوء، رؤية ضبابية\n**جلوكوما حادة:** ألم شديد، غثيان، هالات حول الضوء\n**التهاب قرنية:** ألم، حساسية ضوء، إفراز\n\n**⚠️ تحويل عاجل لطبيب عيون:**\n- فقدان بصر مفاجئ\n- ألم شديد\n- عدم تحسن خلال 48 ساعة\n- إصابة كيميائية → غسل فوري 20 دقيقة', 'ar', 'Clinical/AAO', 5, true),
('symptom_guide', 'ear_pain', ARRAY['ألم أذن','التهاب أذن','سمع','طنين'], 'ألم الأذن', E'## ألم الأذن\n\n**التهاب أذن وسطى:**\n- أطفال، حمى، بكاء\n- العلاج: أموكسيسيلين 40 ملغ/كغ × 3 لمدة 5 أيام\n- مراقبة 48 ساعة للحالات الخفيفة\n\n**التهاب أذن خارجية:**\n- سباحة، حكة، إفراز\n- العلاج: قطرة سيبروفلوكساسين + ديكساميثازون\n\n**أسباب أخرى:**\n- شمع متراكم\n- التهاب مفصل الفك\n- ألم منعكس من الأسنان أو البلعوم\n\n**⚠️ تحويل:** إفراز دموي، شلل وجهي، التهاب خشاء (ألم خلف الأذن مع تورم)', 'ar', 'NICE/AAO', 5, true),
('symptom_guide', 'back_pain', ARRAY['ألم ظهر','أسفل الظهر','عرق النسا','فقرات'], 'ألم أسفل الظهر', E'## ألم أسفل الظهر\n\n**ميكانيكي (90%):**\n- شد عضلي\n- تنكس أقراص\n- العلاج: نشاط تدريجي، مسكنات، علاج طبيعي\n\n**عرق النسا:**\n- ألم يمتد للساق تحت الركبة\n- العلاج: تحفظي 6-8 أسابيع\n- MRI إذا لم يتحسن\n\n**⚠️ علامات الخطر (متلازمة ذيل الفرس):**\n- فقدان السيطرة على البول/البراز\n- تنميل حول الشرج\n- ضعف في كلتا الساقين\n→ **تحويل جراحي طارئ**\n\n**أعلام حمراء أخرى:** عمر > 50 سنة أو < 20، نقص وزن، حمى، سرطان سابق', 'ar', 'NICE/ACP', 5, true),
('symptom_guide', 'weight_loss', ARRAY['نقص وزن','فقدان وزن','نحافة','هزال'], 'نقص الوزن غير المبرر', E'## نقص الوزن غير المبرر\n\n**التعريف:** فقدان > 5% من الوزن خلال 6-12 شهر بدون قصد\n\n**الأسباب:**\n- سكري غير مسيطر عليه\n- فرط درقية\n- أورام خبيثة\n- سل\n- HIV\n- اكتئاب\n- سوء امتصاص (داء سيلياك)\n\n**الفحوصات:**\n- CBC، ESR، CRP\n- سكر صائم، HbA1c\n- TSH\n- وظائف كبد وكلى\n- صورة صدر\n- فحص HIV\n\n**تحويل:** فقدان > 10%، كتلة محسوسة، أعراض مقلقة', 'ar', 'Clinical', 5, true),
('symptom_guide', 'fatigue', ARRAY['تعب','إرهاق','إعياء','خمول'], 'الإرهاق المزمن', E'## الإرهاق المزمن\n\n**أسباب شائعة:**\n- فقر دم\n- قصور درقية\n- سكري\n- اكتئاب/قلق\n- اضطراب نوم\n- نقص حديد/فيتامين D/B12\n\n**أسباب خطيرة:**\n- أورام\n- فشل قلب\n- فشل كلوي/كبدي\n- أمراض مناعية\n\n**الفحوصات:**\n- CBC، فيريتين\n- TSH\n- سكر، HbA1c\n- وظائف كبد وكلى\n- فيتامين D، B12\n- ESR\n\n**معايير الإحالة:** تعب > 3 أشهر مع فحوصات طبيعية → تقييم متلازمة التعب المزمن', 'ar', 'NICE/Clinical', 5, true),
('symptom_guide', 'edema_swelling', ARRAY['تورم','انتفاخ','وذمة','احتباس سوائل'], 'التورم والوذمة', E'## التورم والوذمة\n\n**طرف واحد:**\n- DVT: ألم + تورم + احمرار → طوارئ\n- إنتان موضعي\n- إصابة / كسر\n- انسداد لمفاوي\n\n**ثنائي الطرف:**\n- فشل قلب: ضيق تنفس + تورم\n- فشل كلوي: بول رغوي + ضغط\n- فشل كبد: استسقاء + يرقان\n- قصور وريدي مزمن\n- أدوية (أملوديبين)\n\n**فحوصات:** ألبومين، وظائف كلى وكبد، BNP، إيكو قلب\n\n**⚠️ طوارئ:** تورم أحادي مفاجئ مؤلم → استبعاد DVT فوراً', 'ar', 'Clinical', 5, true);
INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('symptom_guide', 'fever_evaluation', ARRAY['حمى','ارتفاع حرارة','سخونة','عدوى'], 'تقييم الحمى', E'## تقييم الحمى\n\n**التعريف:** حرارة > 38°C\n\n**أسباب شائعة:**\n- عدوى تنفسية علوية\n- التهاب مسالك بولية\n- التهاب رئوي\n- ملاريا (مناطق موبوءة)\n\n**فحوصات أساسية:** CBC، بول، صورة صدر، زراعة دم\n\n**⚠️ تحويل فوري:**\n- حمى + تصلب رقبة (سحايا)\n- حمى + طفح لا يختفي بالضغط\n- حمى > 40°C مع تغير وعي\n- حمى عند رضيع < 3 أشهر\n- حمى مع نقص مناعة', 'ar', 'NICE/WHO', 5, true),
('symptom_guide', 'dyspnea', ARRAY['ضيق تنفس','صعوبة تنفس','نهجة','لهاث'], 'ضيق التنفس', E'## ضيق التنفس\n\n**حاد:**\n- ربو / نوبة حادة\n- انصمام رئوي\n- استرواح صدري\n- وذمة رئوية\n- التهاب رئوي\n\n**مزمن:**\n- COPD\n- فشل قلب\n- تليف رئوي\n- فقر دم شديد\n- قلق\n\n**تقييم:** SpO2، معدل التنفس، ABG، صورة صدر، ECG، BNP\n\n**⚠️ طوارئ:** SpO2 < 92%، عدم القدرة على الكلام، زرقة، استخدام عضلات إضافية', 'ar', 'BTS/Clinical', 5, true),
('symptom_guide', 'nausea_vomiting', ARRAY['غثيان','قيء','استفراغ','تقيؤ'], 'الغثيان والقيء', E'## الغثيان والقيء\n\n**أسباب معدية:** التهاب معدة، قرحة، انسداد\n**أسباب عصبية:** صداع نصفي، ارتفاع ضغط داخل الجمجمة\n**أسباب أيضية:** DKA، فشل كلوي، حمل\n**أدوية:** مسكنات، مضادات حيوية\n\n**العلاج:**\n- ميتوكلوبراميد 10 ملغ × 3\n- أوندانسيترون 4 ملغ عند الحاجة\n- معالجة السبب\n\n**⚠️ طوارئ:** قيء دموي، قيء مع صداع شديد، جفاف شديد، ألم بطن حاد', 'ar', 'Clinical', 5, true),
('symptom_guide', 'constipation', ARRAY['إمساك','صعوبة تبرز','قبض','بطء أمعاء'], 'الإمساك', E'## الإمساك\n\n**أسباب شائعة:**\n- قلة الألياف والسوائل\n- قلة النشاط\n- أدوية (أفيونات، حديد، مضادات اكتئاب)\n- قصور درقية\n\n**العلاج التدريجي:**\n1. ألياف + سوائل + نشاط\n2. لاكتولوز 15-30 مل\n3. بيساكوديل أو سينا\n4. حقنة شرجية إذا لزم\n\n**⚠️ إنذار:**\n- إمساك حديث > 50 سنة → استبعاد سرطان قولون\n- دم في البراز\n- نقص وزن\n- إمساك + انتفاخ + قيء → انسداد', 'ar', 'NICE/Clinical', 5, true),
('symptom_guide', 'sore_throat', ARRAY['التهاب حلق','بلعوم','لوزتين','بلع مؤلم'], 'التهاب الحلق', E'## التهاب الحلق\n\n**فيروسي (70-80%):**\n- سيلان أنف، سعال\n- علاج عرضي: مسكنات + سوائل دافئة\n\n**بكتيري (Strep A):**\n- معايير Centor: حمى، إفراز لوزي، عقد لمفاوية، بدون سعال\n- 3-4 معايير: مضاد حيوي\n- فينوكسي ميثيل بنسلين أو أموكسيسيلين × 10 أيام\n\n**⚠️ تحويل:**\n- عدم القدرة على البلع أو فتح الفم\n- ضيق تنفس\n- خراج حول اللوزة (تورم أحادي)\n- صعوبة تنفس عند الأطفال (خناق)', 'ar', 'NICE/IDSA', 5, true),
('symptom_guide', 'vaginal_bleeding', ARRAY['نزيف مهبلي','نزيف رحمي','دورة غير منتظمة','نزيف بعد سن اليأس'], 'النزيف المهبلي غير الطبيعي', E'## النزيف المهبلي غير الطبيعي\n\n**في سن الإنجاب:**\n- حمل خارجي → اختبار حمل فوري\n- إجهاض\n- اضطراب هرموني\n- أورام ليفية\n- عدوى\n\n**بعد سن اليأس:**\n- يجب استبعاد سرطان بطانة الرحم\n- سونار + خزعة بطانة\n\n**⚠️ طوارئ:**\n- نزيف غزير مع هبوط ضغط\n- نزيف مع اختبار حمل إيجابي + ألم\n- نزيف بعد سن اليأس → إحالة عاجلة خلال أسبوعين', 'ar', 'NICE/RCOG', 5, true),
('symptom_guide', 'jaundice', ARRAY['يرقان','اصفرار','كبد','بيليروبين'], 'اليرقان', E'## اليرقان\n\n**قبل كبدي:** انحلال دم → بيليروبين غير مباشر مرتفع\n**كبدي:** التهاب كبد، تشمع، أدوية → ارتفاع الإنزيمات\n**بعد كبدي:** حصوة، ورم بنكرياس → بيليروبين مباشر مرتفع\n\n**فحوصات:** بيليروبين (مباشر وغير مباشر)، ALT، AST، ALP، GGT، ألبومين، INR، سونار بطن\n\n**⚠️ تحويل عاجل:**\n- يرقان مع حمى وألم (التهاب أقنية صفراوية)\n- يرقان بدون ألم + نقص وزن (ورم)\n- يرقان حديثي الولادة خلال أول 24 ساعة', 'ar', 'BSG/Clinical', 5, true);
